    const uint32_t strideH = stride ? static_cast<uint32_t>(stride[1]) : 1u;
    const uint32_t strideW = stride ? static_cast<uint32_t>(stride[2]) : 1u;

    const uint32_t padD = padding ? static_cast<uint32_t>(padding[0]) : 0u;
    const uint32_t padH = padding ? static_cast<uint32_t>(padding[1]) : 0u;
    const uint32_t padW = padding ? static_cast<uint32_t>(padding[2]) : 0u;

    const uint32_t outPadD = output_padding ? static_cast<uint32_t>(output_padding[0]) : 0u;
    const uint32_t outPadH = output_padding ? static_cast<uint32_t>(output_padding[1]) : 0u;
    const uint32_t outPadW = output_padding ? static_cast<uint32_t>(output_padding[2]) : 0u;

    const uint32_t dilD = dilation ? static_cast<uint32_t>(dilation[0]) : 1u;
    const uint32_t dilH = dilation ? static_cast<uint32_t>(dilation[1]) : 1u;
    const uint32_t dilW = dilation ? static_cast<uint32_t>(dilation[2]) : 1u;

    const uint32_t groups = groups_ptr ? static_cast<uint32_t>(groups_ptr[0]) : 1u;

    // Only groups=1 supported in kernel implementation
    (void)groups;

    // out_channels = w_shape[1] * groups
    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetDim(1)) * (groups_ptr ? static_cast<uint32_t>(groups_ptr[0]) : 1u);

